return await (async function(eda) {
  const fixtureName = '__codex_example___IPCB_PrimitiveAttribute_setState_Value_' + Date.now();
  const currentDocument = await eda.dmt_SelectControl.getCurrentDocumentInfo();
  if (!currentDocument) {
    throw new Error('当前没有活动文档，先打开一个可操作的文档页。');
  }
  if (currentDocument.documentType !== 3) {
    throw new Error('当前文档类型不是 PCB，请先切到 PCB 再运行这个案例。');
  }
  const selectedPrimitiveIds = eda.pcb_SelectControl.getAllSelectedPrimitives_PrimitiveId();
  const primitiveId = Array.isArray(selectedPrimitiveIds) ? selectedPrimitiveIds[0] : undefined;
  if (!primitiveId) {
    throw new Error('请先在PCB画布上选中一个与 IPCB_PrimitiveAttribute 匹配的图元，再运行这个案例。');
  }
  const fetched = await eda.pcb_PrimitiveAttribute.get([primitiveId]);
  const primitive = Array.isArray(fetched) ? fetched[0] : fetched;
  if (!primitive) { throw new Error('没有取到目标图元对象。'); }
  const editable = primitive.toAsync ? primitive.toAsync() : primitive;
  const before = editable.getState_Value ? editable.getState_Value() : undefined;
  editable.setState_Value('value');
  if (editable.done) { editable.done(); }
  const afterFetch = await eda.pcb_PrimitiveAttribute.get([primitiveId]);
  const afterPrimitive = Array.isArray(afterFetch) ? afterFetch[0] : afterFetch;
  const after = afterPrimitive?.getState_Value ? afterPrimitive.getState_Value() : undefined;
  return { fixtureName, primitiveId, before, after };
})(eda);
